import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
	type: 'n8n-nodes-base.manualTrigger',
	version: 1,
	config: { name: 'Manual Trigger' },
});

const setNode = node({
	type: 'n8n-nodes-base.set',
	version: 3.4,
	config: {
		name: 'preview auto-open test',
		parameters: {
			mode: 'manual',
			assignments: {
				assignments: [
					{
						id: 'field1',
						name: 'message',
						value: 'Hello from n8n',
						type: 'string',
					},
				],
			},
		},
	},
});

export default workflow('preview-auto-open-test', 'preview auto-open test').add(manualTrigger).to(setNode);

